/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const n = nums.length;
    let count = 0;

    // Build adjacency matrix for O(1) edge lookup in induced subgraph check
    const adj = Array(n).fill(0).map(() => Array(n).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = adj[v][u] = true;
    }

    // Iterate over all non-empty subsets s. There are 2^n - 1 such subsets.
    // We use bitmasks from 1 to 2^n - 1.
    const totalSubsets = 1 << n;

    for (let mask = 1; mask < totalSubsets; mask++) {
        const subsetNodes = [];
        let sum = 0;

        // 1. Determine subset nodes and calculate sum
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                subsetNodes.push(i);
                sum += nums[i];
            }
        }

        // 2. Check if the sum of values is even
        if (sum % 2 !== 0) {
            continue; // Skip if sum is odd
        }

        // 3. Check if the induced subgraph is connected
        const isConnected = checkConnectivity(n, adj, mask, subsetNodes);

        if (isConnected) {
            count++;
        }
    }

    return count;
}

/**
 * Checks if the subgraph induced by the nodes represented by the mask is connected.
 * @param {number} n Total number of nodes.
 * @param {boolean[][]} adj Adjacency matrix of the original graph.
 * @param {number} mask Bitmask representing the subset of nodes s.
 * @param {number[]} subsetNodes List of nodes in s.
 * @returns {boolean} True if the induced subgraph is connected, false otherwise.
 */
function checkConnectivity(n, adj, mask, subsetNodes) {
    if (subsetNodes.length === 1) {
        return true; // A single node graph is always connected
    }

    const startNode = subsetNodes[0];
    const visited = new Set();
    const queue = [startNode];
    visited.add(startNode);
    let visitedCount = 0;

    // BFS starting from an arbitrary node in the subset
    while (queue.length > 0) {
        const u = queue.shift();
        visitedCount++;

        for (const v of subsetNodes) {
            if (u === v) continue;

            // Check if there is an edge between u and v in the original graph
            // AND v has not been visited yet
            if (adj[u][v] && !visited.has(v)) {
                visited.add(v);
                queue.push(v);
            }
        }
    }

    // If the count of visited nodes equals the size of the subset, it's connected.
    return visitedCount === subsetNodes.length;
}

