import scala.collection.mutable

object Solution {
  def nums(nums: Array[Long], edges: Array[Array[Long]]): Long = {
    val n = nums.length
    var count: Long = 0

    // Build adjacency matrix for O(1) edge lookup in induced subgraph check
    val adj = Array.ofDim[Boolean](n) { BooleanArray(n) }
    for (edge in edges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      adj(u)(v) = true
      adj(v)(u) = true
    }

    // Iterate over all non-empty subsets s. There are 2^n - 1 such subsets.
    val totalSubsets = 1 << n

    for (mask <- 1 until totalSubsets) {
      val subsetNodes = mutable.ArrayBuffer[Int]()
      var sum: Long = 0

      // 1. Determine subset nodes and calculate sum
      for (i <- 0 until n) {
        if ((mask >> i) & 1 == 1) {
          subsetNodes += i
          sum += nums(i)
        }
      }

      // 2. Check if the sum of values is even
      if (sum % 2 != 0) {
        continue // Skip if sum is odd
      }

      // 3. Check if the induced subgraph is connected
      if (checkConnectivity(n, adj, mask, subsetNodes)) {
        count += 1
      }
    }

    count
  }

  /**
   * Checks if the subgraph induced by the nodes represented by the mask is connected.
   */
  private def checkConnectivity(n: Int, adj: Array[BooleanArray], mask: Int, subsetNodes: mutable.ArrayBuffer[Int]): Boolean = {
    if (subsetNodes.isEmpty) {
      // Should not happen based on main loop starting from mask=1
      return false
    }
    if (subsetNodes.size == 1) {
      return true // A single node graph is always connected
    }

    val startNode = subsetNodes(0)
    val visited = mutable.HashSet[Int]()
    val queue = mutable.ArrayBuffer[Int]()

    queue.append(startNode)
    visited.add(startNode)
    var visitedCount = 0

    // BFS starting from an arbitrary node in the subset
    while (queue.nonEmpty) {
      val u = queue.remove(0)
      visitedCount += 1

      for (v <- subsetNodes) {
        if (u == v) continue

        // Check if there is an edge between u and v in the original graph
        // AND v has not been visited yet
        if (adj(u)(v) && !visited.contains(v)) {
          visited.add(v)
          queue.append(v)
        }
      }
    }

    // If the count of visited nodes equals the size of the subset, it's connected.
    visitedCount == subsetNodes.size
  }
}
