        const subsetNodes = [];
        let sum = 0;

        // 1. Determine subset nodes and calculate sum
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                subsetNodes.push(i);
                sum += nums[i];
            }
        }

        // 2. Check if the sum of values is even
