object Solution {
  def solve(nums: Array[Long], edges: Array[Array[Long]]): Long = {
    val n = nums.length
    var count: Long = 0

    // Build adjacency matrix for O(1) edge lookup in induced subgraph check
    val adj = Array.ofDim[Boolean](n) { Array.ofDim[Boolean](n) }
    for (edge in edges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      adj(u)(v) = true
      adj(v)(u) = true
    }

    // Iterate over all non-empty subsets s. There are 2^n - 1 such subsets.
    val totalSubsets = 1 << n

    for (mask <- 1 until totalSubsets) {
      var sum: Long = 0
      val subsetNodes = mutable.ArrayBuffer[Int]()

      // 1. Determine subset nodes and calculate sum
      for (i <- 0 until n) {
        if ((mask >> i) & 1 == 1) {
          subsetNodes += i
          sum += nums(i)
        }
      }

      // 2. Check if the sum of values is even
      if (sum % 2 != 0) {
        continue // Skip if sum is odd
      }

      // 3. Check if the induced subgraph is connected
      val isConnected = checkConnectivity(n, adj, mask, subsetNodes)

      if (isConnected) {
        count += 1
      }
    }

    count
  }

  /**
   * Checks if the subgraph induced by the nodes represented by the mask is connected.
   */
  private def checkConnectivity(n: Int, adj: Array[Array[Boolean]], mask: Int, subsetNodes: scala.collection.mutable.ArrayBuffer[Int]): Boolean = {
    if (subsetNodes.size == 1) {
      return true // A single node graph is always connected
    }

    val startNode = subsetNodes(0)
    val visited = scala.collection.mutable.Set[Int]()
    val queue = scala.collection.mutable.Queue.apply(startNode)
    visited.add(startNode)
    var visitedCount: Int = 0

    // BFS starting from an arbitrary node in the subset
    while (queue.nonEmpty) {
      val u = queue.dequeue()
      visitedCount += 1

      // Iterate over all nodes in the subset to find neighbors in the induced subgraph
      for (v <- subsetNodes) {
        if (u == v) continue

        // Check if there is an edge between u and v AND v has not been visited yet
        if (adj(u)(v) && !visited.contains(v)) {
          visited.add(v)
          queue.enqueue(v)
        }
      }
    }

    // If the count of visited nodes equals the size of the subset, it's connected.
    visitedCount == subsetNodes.size
